import{_ as e,o as s,c as n,a2 as o}from"./chunks/framework.DCVnL8g5.js";const h=JSON.parse('{"title":"Dominio y casos de uso","description":"","frontmatter":{},"headers":[],"relativePath":"full-stack/arquitectura/hexagonal/02-dominio-y-casos-de-uso.md","filePath":"full-stack/arquitectura/hexagonal/02-dominio-y-casos-de-uso.md","lastUpdated":1782521464000}'),i={name:"full-stack/arquitectura/hexagonal/02-dominio-y-casos-de-uso.md"};function t(l,a,d,p,c,r){return s(),n("div",null,[...a[0]||(a[0]=[o(`<h1 id="dominio-y-casos-de-uso" tabindex="-1">Dominio y casos de uso <a class="header-anchor" href="#dominio-y-casos-de-uso" aria-label="Permalink to &quot;Dominio y casos de uso&quot;">​</a></h1><p>El centro de la arquitectura hexagonal son las reglas de negocio y las acciones que la aplicacion permite ejecutar.</p><h2 id="dominio" tabindex="-1">Dominio <a class="header-anchor" href="#dominio" aria-label="Permalink to &quot;Dominio&quot;">​</a></h2><p>El dominio contiene conceptos del negocio:</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Order</span></span>
<span class="line"><span>Money</span></span>
<span class="line"><span>Invoice</span></span>
<span class="line"><span>Course</span></span>
<span class="line"><span>Enrollment</span></span></code></pre></div><p>Debe ser independiente de frameworks, controladores, ORM y proveedores externos.</p><h2 id="casos-de-uso" tabindex="-1">Casos de uso <a class="header-anchor" href="#casos-de-uso" aria-label="Permalink to &quot;Casos de uso&quot;">​</a></h2><p>Un caso de uso representa una intencion:</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ConfirmOrder</span></span>
<span class="line"><span>PublishCourse</span></span>
<span class="line"><span>CancelEnrollment</span></span>
<span class="line"><span>CapturePayment</span></span></code></pre></div><p>No es simplemente un metodo CRUD. Debe expresar algo que el sistema permite hacer.</p><h2 id="entrada-del-caso-de-uso" tabindex="-1">Entrada del caso de uso <a class="header-anchor" href="#entrada-del-caso-de-uso" aria-label="Permalink to &quot;Entrada del caso de uso&quot;">​</a></h2><p>Usa comandos o DTOs internos:</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ConfirmOrderCommand</span></span>
<span class="line"><span>  orderId</span></span>
<span class="line"><span>  requestedBy</span></span></code></pre></div><p>Evita pasar objetos HTTP, modelos de ORM o eventos externos directamente al caso de uso.</p><h2 id="salida-del-caso-de-uso" tabindex="-1">Salida del caso de uso <a class="header-anchor" href="#salida-del-caso-de-uso" aria-label="Permalink to &quot;Salida del caso de uso&quot;">​</a></h2><p>Puede devolver:</p><ul><li>Resultado de operacion.</li><li>DTO de lectura.</li><li>Identificador creado.</li><li>Nada, si la accion solo produce efecto.</li><li>Error de dominio o aplicacion.</li></ul><h2 id="dependencias" tabindex="-1">Dependencias <a class="header-anchor" href="#dependencias" aria-label="Permalink to &quot;Dependencias&quot;">​</a></h2><p>El caso de uso puede depender de puertos:</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>OrderRepository</span></span>
<span class="line"><span>PaymentGateway</span></span>
<span class="line"><span>EventPublisher</span></span>
<span class="line"><span>Clock</span></span></code></pre></div><p>No debe depender de implementaciones concretas.</p><h2 id="checklist" tabindex="-1">Checklist <a class="header-anchor" href="#checklist" aria-label="Permalink to &quot;Checklist&quot;">​</a></h2><ul><li>Los casos de uso tienen nombres de negocio.</li><li>El dominio no importa tecnologia.</li><li>La entrada esta desacoplada del transporte.</li><li>Las dependencias externas son puertos.</li><li>Las reglas criticas viven en dominio o aplicacion, no en adaptadores.</li></ul>`,23)])])}const m=e(i,[["render",t]]);export{h as __pageData,m as default};
